 1	import { type Ref, useEffect, useMemo, useState } from 'react';
 2	
 3	import {
 4	  Badge,
 5	  MenuToggle,
 6	  type MenuToggleElement,
 7	  Select as PfSelect,
 8	  SelectList,
 9	  SelectOption,
10	  Split,
11	  SplitItem,
12	} from '@patternfly/react-core';
13	import { useForkliftTranslation } from '@utils/i18n';
14	
15	import type { CheckboxAttr } from '../utils/types';
16	
17	type FilterValueMultiSelectProps<T> = {
18	  attribute: CheckboxAttr<T>;
19	  selected: Set<string>;
20	  onToggle: (optId: string) => void;
21	  /** When this key changes (e.g., active attribute id), the dropdown closes */
22	  closeKey?: string;
23	  width?: number;
24	};
25	
26	const FilterValueMultiSelect = <T,>({
27	  attribute,
28	  closeKey,
29	  onToggle,
30	  selected,
31	  width = 220,
32	}: FilterValueMultiSelectProps<T>) => {
33	  const { t } = useForkliftTranslation();
34	  const [isOpen, setOpen] = useState(false);
35	
36	  // Close when switching active attribute (preserves your old behavior)
37	  useEffect(() => {
38	    setOpen(false);
39	  }, [closeKey]);
40	
41	  const selectedValues = useMemo(() => Array.from(selected ?? new Set<string>()), [selected]);
42	
43	  return (
44	    <PfSelect
45	      role="menu"
46	      id={`filter-checks-${attribute.id}`}
47	      isOpen={isOpen}
48	      selected={selectedValues}
49	      onSelect={(_e, value) => {
50	        onToggle(String(value));
51	      }}
52	      onOpenChange={(open) => {
53	        setOpen(open);
54	      }}
55	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
56	        <MenuToggle
57	          ref={toggleRef}
58	          onClick={() => {
59	            setOpen((open) => !open);
60	          }}
61	          isExpanded={isOpen}
62	          style={{ width }}
63	        >
64	          {t('Filter by {{activeFilterLabel}}', {
65	            activeFilterLabel: attribute.label.toLocaleLowerCase(),
66	          })}
67	          {selected.size ? <Badge isRead>{selected.size}</Badge> : null}
68	        </MenuToggle>
69	      )}
70	      shouldFocusToggleOnSelect
71	      isScrollable
72	    >
73	      <SelectList isAriaMultiselectable>
74	        {attribute.options.map((option) => (
75	          <SelectOption
76	            key={option.id}
77	            value={option.id}
78	            hasCheckbox
79	            isSelected={selected.has(option.id)}
80	          >
81	            <Split>
82	              {option.icon ? <SplitItem className="pf-v6-u-mr-sm">{option.icon}</SplitItem> : null}
83	              <SplitItem>{option.label ?? option.id}</SplitItem>
84	            </Split>
85	          </SelectOption>
86	        ))}
87	      </SelectList>
88	    </PfSelect>
89	  );
90	};
91	
92	export default FilterValueMultiSelect;

